17	attention_sink_fa2_decl = r"""
18	struct AttentionSink : AttentionVariantBase {
19	  static constexpr bool use_softmax = true;
20	
21	  uint32_t window_left, qo_len, kv_len;
22	  float sm_scale_log2;
23	
24	  // Create closure
25	  template <typename Params>
26	  __device__ __host__ AttentionSink(const Params& params, uint32_t batch_idx,
27	                                   uint8_t* smem_ptr) {
28	    qo_len = params.get_qo_len(batch_idx);
29	    kv_len = params.get_kv_len(batch_idx);
30	    window_left = (params.window_left >= 0) ? params.window_left : kv_len;
31	    sm_scale_log2 = params.sm_scale * math::log2e;
32	  }
33	
34	  REGISTER_LOGITS_MASK(params, batch_idx, qo_idx, kv_idx, qo_head_idx, kv_head_idx, {
35	    return (kv_idx + qo_len + window_left >= kv_len + qo_idx);
36	  })
37	
38	  REGISTER_M_D_UPDATE(params, kv_tile_idx, qo_head_idx, m, d, scale, {
39	    float log_sink = (kv_tile_idx == 0 && qo_head_idx < params.num_qo_heads) ? params.sink[qo_head_idx] * math::log2e : -math::inf;
40	    float m_new = (log_sink > m) ? log_sink : m;
41	    scale = math::ptx_exp2(m - m_new);
42	    float d_new = math::ptx_exp2(log_sink - m_new) + d * scale;
43	    // Update m and d
44	    m = m_new;
45	    d = d_new;
46	  })
47	
48	  REGISTER_OUTPUT_TRANSFORM(params, output, batch_idx, qo_idx, qo_head_idx, m, d, scale, {
49	    float d_rcp = (m != -math::inf) ? math::ptx_rcp(d) : 0.f;
50	    return output * scale * d_rcp;
51	  });
52	};
53	"""
54	
55	attention_sink_fa3_decl = r"""
56	
57	template <int NUM_ROWS_PER_THREAD>
58	struct OnlineSoftmaxWithSink {
59	  constexpr static float fill_value = -math::inf;
60	  using TensorT = decltype(make_tensor<float>(Shape<Int<NUM_ROWS_PER_THREAD>>{}));
61	  TensorT row_max, row_sum, scores_scale;
62	  float sm_scale_log2;
63	  float log_sink;
64	
65	  CUTLASS_DEVICE OnlineSoftmaxWithSink(float sm_scale_log2, float log_sink) : sm_scale_log2(sm_scale_log2), log_sink(log_sink) {
66	    clear(scores_scale);
67	  };
68	
69	  __forceinline__ __device__ TensorT get_lse() const { return row_sum; }
70	
71	  template <bool init, typename Tensor0>
72	  __forceinline__ __device__ void update(Tensor0& acc_s) {
73	    // Reshape acc_s from ((2, 2, V), MMA_M, MMA_N) to (nrow=(2, MMA_M), ncol=(2, V, MMA_N))
74	    Tensor scores = make_tensor(acc_s.data(), convert_layout_acc_rowcol(acc_s.layout()));
75	
76	    static_assert(decltype(size<0>(scores))::value == NUM_ROWS_PER_THREAD);
77	    if constexpr (init) {
78	      reduce_max</*init=*/true>(scores, row_max);
79	      scale_apply_exp2(scores, row_max, sm_scale_log2);
80	      reduce_sum</*init=*/true, /*warp_reduce=*/false>(scores, row_sum);
81	    } else {
82	      // update row_max
83	      Tensor scores_max_prev = make_fragment_like(row_max);
84	      cute::copy(row_max, scores_max_prev);
85	      reduce_max</*init=*/false>(scores, row_max);
86	      // update scores_scale and scale row_sum
87	#pragma unroll
88	      for (int mi = 0; mi < size(row_max); ++mi) {
89	        float scores_max_cur = row_max(mi);
90	        scores_scale(mi) = exp2f((scores_max_prev(mi) - scores_max_cur) * sm_scale_log2);
91	        row_sum(mi) *= scores_scale(mi);
92	      }
93	      // perform exp2 on scores
94	      scale_apply_exp2(scores, row_max, sm_scale_log2);
95	      // update row_sum
96	      reduce_sum</*init=*/false, /*warp_reduce=*/false>(scores, row_sum);
97	    }
98	  };
99	
100	  template <typename Tensor0>
101	  __forceinline__ __device__ void finalize(Tensor0& acc_s, float pv_scale = 1.f) {
102	    // Reshape acc_s from ((2, 2, V), MMA_M, MMA_N) to (nrow=(2, MMA_M), ncol=(2, V, MMA_N))
103	    // Note (Yilong): use pv_scale to dequantize the output
104	    Tensor scores = make_tensor(acc_s.data(), convert_layout_acc_rowcol(acc_s.layout()));
105	    static_assert(decltype(size<0>(scores))::value == NUM_ROWS_PER_THREAD);
106	    SumOp<float> sum_op;
107	    quad_allreduce_(row_sum, row_sum, sum_op);
